  2088→// and the provided newValue argument. setAtomicToNewer returns whether the
  2089→// atomic value was updated and what the previous value was.
  2090→func setAtomicToNewer(value *atomic.Int64, newValue int64) (previous int64, updated bool) {
  2091→	for {
  2092→		current := value.Load()
  2093→		if current >= newValue {
