func isTransientError(err error) bool {
	if err == nil {
		return false
	}

	// Context errors should not be retried - they indicate the caller canceled or timed out
	if errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded) {
		return false
	}

